+    fn from_time_creates_valid_config() {
+        init_test("from_time_creates_valid_config");
+        let cfg = LabConfig::from_time();
+        // seed should be set from system time (non-deterministic but valid)
+        assert_eq!(cfg.entropy_seed, cfg.seed);
