+        let chaos = cfg.chaos.as_ref().unwrap();
+        // Chaos seed derived from main seed + 0xCAFE_BABE
+        let dbg = format!("{chaos:?}");
+        assert!(!dbg.is_empty());
+        crate::test_complete!("with_chaos_derives_seed");
+    }
 }

